THE CLAIM:
{
 "title": "Country map uses colo-only demand, overweighting Germany and NL",
 "narrative": "The model splits demand by country using colo megawatts divided by colo megawatts. But rack-PDU demand tracks total installed IT load, and about a third of that load sits outside colocation with a different country mix. Germany's installed load exceeds its colo figure by about 1,000MW, so a colo-based map overstates Germany and the Netherlands in the Year-1 plan.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "EUDCA: colo and hyperscale is only two-thirds of Europe's power.",
   "refs": [
    "digest:geo-region-denominator#c11",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "propagation",
   "text": "Gap varies by country, shifting the €300M across markets.",
   "refs": [
    "ledger:geo.DE",
    "ledger:geo.CH",
    "ledger:geo.PL"
   ]
  },
  {
   "step": "model-impact",
   "text": "Plan overweights Germany and NL, misses Swiss and Polish demand.",
   "refs": [
    "profile:Who is the primary buyer you'll sell through first?",
    "ledger:geo.NL",
    "digest:geo-region-denominator#c14"
   ]
  }
 ],
 "falsifier": "A single-source table of total installed IT load for all CE-7 countries whose per-country shares match the current colo-based shares within 3 percentage points.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "Status and development of the German data centre landscape – Executive Summary",
   "sourceType": "industry-report",
   "publisher": "BMWK (Federal Ministry for Economic Affairs and Climate Action)",
   "date": "2025-03",
   "excerpt": "With over 2,000 data centres and an installed IT power demand of over 2,700 MW, Germany is already the largest centre for digital infrastructure in Europe.",
   "url": "https://www.bundeswirtschaftsministerium.de/Redaktion/EN/Publikationen/Digitale-Welt/status-and-development-of-the-german-data-centre-landscape-executive-summary.pdf?__blob=publicationFile&v=2",
   "attached": true
  },
  {
   "title": "New 2026 State of European Data Centres",
   "sourceType": "industry-report",
   "publisher": "EUDCA",
   "date": "2026",
   "excerpt": "commercial colocation and hyperscale facilities now provide more than two-thirds of Europe’s IT power, driven by the growing demand for cloud and AI.",
   "url": "https://www.eudca.org/new-2026-state-of-european-data-centres",
   "attached": true
  },
  {
   "title": "Switzerland Colocation Data Center Portfolio Analysis Report 2025",
   "sourceType": "industry-report",
   "publisher": "Arizton / ResearchAndMarkets",
   "date": "2026-01-06",
   "excerpt": "The existing IT load capacity stands at around 280+ MW, while the upcoming pipeline is set to add nearly 900 MW.",
   "url": "https://www.businesswire.com/news/home/20260106992077/en/Switzerland-Colocation-Data-Center-Portfolio-Analysis-Report-2025-STACK-Infrastructure-Green-Datacenter-Digital-Realty-and-Vantage-Data-Centers-Remain-the-Major-Forces-Shaping-the-Market---ResearchAndMarkets.com",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "geo.DE",
  "label": "Germany",
  "kind": "estimated",
  "value": 0.5,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "geography",
  "dimensionValue": "DE",
  "sensitivityRange": {
   "low": 0.42,
   "high": 0.53
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "DE colo 1,737 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.503 → 0.50 (normalized)",
   "crossCheck": "Installed-IT-load method (BMWK >2,700 MW ÷ CE-7 installed) → 0.42 — sets the low end"
  },
  "provenance": {
   "rationale": "Two independent capacity methods bracket 0.42–0.53; colo-scope figure is primary → inferred.",
   "promotionPath": "Reconcile colo vs total-installed scopes with one 2025 vendor-revenue split → verified."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Germany 1,737 MW of colocation and scale-colocation IT power in 2025 — the largest CE base (NL 951, CH 274, PL 228, CZ 79, AT 68).",
    "attached": true
   },
   {
    "title": "Status and development of the German data centre landscape",
    "sourceType": "industry-report",
    "publisher": "BMWK (Federal Ministry for Economic Affairs)",
    "date": "2025-03",
    "excerpt": "With over 2,000 data centres and an installed IT power demand of over 2,700 MW, Germany is already the largest centre for digital infrastructure in Europe.",
    "attached": true
   }
  ]
 },
 {
  "id": "geo.NL",
  "label": "Netherlands",
  "kind": "estimated",
  "value": 0.28,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "geography",
  "dimensionValue": "NL",
  "sensitivityRange": {
   "low": 0.24,
   "high": 0.31
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "NL colo 951 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.276 → 0.28 (normalized)",
   "crossCheck": "Dutch Data Center Association: national colo 924 MW (2024) — consistent scale"
  },
  "provenance": {
   "rationale": "Statista and the national association agree within ~3% → inferred, triangulated."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
